//#region extension/src/renderer/ListenForEvents.ts
function listenForEvents(lynxAPI) {
	lynxAPI.events.on("card_install_addStep", ({ id, addStep }) => {
		if (ModulesThatSupportPython.includes(id)) {
			const { index, title, content } = getStep(id);
			addStep(index, title, content);
		}
	});
	lynxAPI.ipcEvents.onChannel("before", storageUtilsChannels.addInstalledCard, (event) => {
		if (event.method !== "send") return;
		const [cardData] = event.args;
		pIpc.findAIVenv(cardData.id, cardData.dir);
	});
}
//#endregion
//#region extension/src/renderer/Extension.tsx
function InitialExtensions(lynxAPI) {
	listenForEvents(lynxAPI);
	setCards(lynxAPI.modulesData?.allCards || []);
	if (lynxAPI.toast) setToast(lynxAPI.toast);
	lynxAPI.addReducer([{
		name: "pythonToolkit",
		reducer: reducer_default
	}]);
	if (typeof window.LynxHub !== "undefined" && window.LynxHub.buildNumber && window.LynxHub.buildNumber > 45 || isDev() && APP_BUILD_NUMBER > 44) lynxAPI.customizePages.tools.add.cardsContainer(ToolsPage);
	else lynxAPI.customizePages.tools.addComponent(ToolsPage);
	lynxAPI.cards.customize.menu.addSection([{
		index: 1,
		components: [CardMenu]
	}]);
	lynxAPI.cards.customize.menu.addModal([{
		key: DepsModalKey,
		component: CardMenuModal
	}]);
	lynxAPI.addCustomHook(CustomHook);
	pIpc.getAppVersion().then((version) => {
		window.lynxVersion = version;
	}).catch(() => {
		console.log("Can't get the app version.");
	});
}
